INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00272', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「出版的書被買走，然後又被脫手，直到來到下一個主人手中，書本才算重生。書就是這樣幾經復活， 在人與人之間建立連結。」 根據上文，下列選項對於書本的解讀，何者最適當？', '["書本放在書店的書架上就只是商品，沒有絲毫意義", "書本有自己的思想，遇見契合的主人就彷彿有了生命", "書本接連被讀者買回家，成為前後任主人間溝通的媒介", "書本的生命週期短暫，需要不斷經過生而死、死而生的循環"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00273', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「當企業領袖看到市場開始變化，於是設法推動組織轉型，此時會面臨矛盾的情況。一方面，需要令 人信服的數據，以提出理由說明轉型的必要，證明公司即將面臨『危急關頭』；另一方面，等到有關 破壞性趨勢和市場變化的公開數據，已足以令人信服時，機會之窗已經縮小了，甚至已經消失。當公 司真正面對危急關頭時，企業領袖會面對嚴酷的現實：在彈性極為重要的時刻，危急關頭的情況卻導 致公司更僵化，妨礙進行變革。」 根據上文，下列敘述何者正確？', '["企業領袖必須等市場數據完全公開，再進行趨勢分析，才符合科學精神", "等市場危機的正式數據被公開時，變革的契機早已逐漸消失，無力回天", "當危急關頭來臨時，組織因受到巨大的壓力，變革成功的機會才會大大提升", "變革是企業領袖最致命弱點，按部就班、穩紮穩打才是企業成長的不二原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00274', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「有關『犯罪測謊』的研究指出：如果一個人有巨大的壓力要讓自己顯得很可信，他的行為反而通常 會讓觀察者覺得他在說謊。一個說真話的人，在他家裡時會平靜地看著你的眼睛，和你討論事情；但 是，當他被叫到法庭上為自己作辯護的時候，卻會一直低頭瞪著自己抖不停的腳。」 根據上文，下列選項何者正確？', '["壓力會使一個人冷靜下來，才能夠清楚表達自己的意見", "說謊的壓力會使人手足無措，更容易暴露出自己的錯誤", "一個人是否說謊，與他的表現鎮定或驚慌沒有直接關係", "不停抖動的手腳和慌張語氣，就是說謊時最直接的反應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00275', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「專注與發散，兩者互為表裡，是大腦運作的兩種不同模式。心智就像一座彈珠檯，專注模式，就是 彈珠檯排列密集的碰撞物，你的心智彈珠在這區間撞出路徑，但思維跑不遠。而發散模式，則是排列 鬆散的碰撞物，心智彈珠雖無法集中火力，但活動範圍卻是海闊天空。因此， 。」 根據上文，下列選項何者最適合做為本段文字的結論？', '["專注比較難，也比較被推崇", "分心不易節制，較不被重視", "發散雖不按理出牌，卻常有妙著", "專注很好，但適度分神，會更好"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00276', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「康德認為外在的自然現象與動物天生的生理欲求，都是無法改變的『他律』。由他律所驅使的行為， 都不是真正的自由，只是出於服從，就像早期飲料的廣告：『順從你的渴望』，便是在說服我們成為渴 望的奴隸。在康德的定義下，完全被『他律』擺布的人就像自由落體中的身體一樣，完全受制於他律， 是不自由的。」 根據上文，下列選項何者最適當？', '["能擺脫他律的掌控，才可能獲得真正的自由", "基本生理欲求的滿足，是擁有自由的起始點", "有錢人想做而能做的事情比較多，所以比窮人自由", "完全隨心所欲而無任何阻礙的人，擁有最大的自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00277', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「手塚治蟲年輕時受迪士尼動畫的影響很大。他在自傳中提到他看了50次《白雪公主》，《小鹿斑比》 則看了80幾次。在迷上迪士尼後，他拚命地臨摹，直到擁有自己的畫風。後來迪士尼發行《獅子王》 時，還發生疑似模仿手塚治蟲《叢林大帝》的問題，這正是不斷研究對手之後， 的明證。所以， 認真研究偶像或對手，也能當作自己成長的養分。」 根據上文，最適合填入文中畫底線處的文句是：', '["操千曲而後曉聲", "青出於藍而勝於藍", "不鳴則已，一鳴驚人", "不入虎穴，焉得虎子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00278', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「冰箱既能如此精確地指向生活的身體，就簡直令人害羞。小時候父母設置了各式天條，最禁忌之一， 就是做客不可開主人家的冰箱。兒童不懂得這裡的羞恥感存在何處，過後才漸漸明白，首先擅自接近 食物，無論如何就代表一種饞相，像是多好吃或多挨餓似的，傷害父母的體面，各種禮儀都是從遮掩 身或心的貪欲開始的；再一層，也是迴護主人，萬一打開了，一片蕭條，大家面面相覷，固然不太好， 萬一裡面有各種好東西，那更加不好了。」 根據上文，下列選項對冰箱的敘述何者正確？', '["能保存各種日常所需食物，是現代生活富裕的象徵", "是家中最禁忌的地方，孩童未經同意不可隨意開啟", "象徵人性中的貪欲，必須要加以限制以免傷害健康", "內容物直接反映使用者的本相，適度遮掩較合禮儀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00279', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「紐約處大西洋之濱，魚很多，釣魚為樂的人亦自不少。長島上便有羊頭塢，幾十條漁船，專載搭客 赴大洋附近各處釣魚。春季一來，釣客漸多。今天是立春，此去又可常去釣魚了。到了夏季七、八月 間，藍魚正盛，可以通夜釣魚。每逢星期日，海面上可有百數十條船，環顧三五里內，盡是漁艇。在 夜色蒼茫下，燈火澈亮，就似另一世界。」 根據上文，下列選項何者最符合文意？', '["紐約人除釣魚外別無嗜好", "釣魚的地點只限於長島海濱", "春季釣客眾多，通宵可見漁火通明", "釣藍魚的旺季是夏季，尤其是週日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00280', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「就我的經驗而言，很少年輕人會設定好人生目標，更別提貫徹終身的目標。其實，職涯之路大部分 只是知道自己今天要往那個方向走，不一定知道終點在那裡。終點並非固定不變的，是隨著你前進時， 不斷自我創造，終點也會跟著改變。在你非常年輕時，也許已經建立一些核心價值，但是隨著時間推 移、生活經驗增長、藉由觀察他人，或閱讀偉大的傳記，你還能發展出更多的核心價值。」 根據上文，下列選項何者最符合文意？', '["目標處於人生的終點，也是我們朝向理想的指南針", "人生價值的終點固定不變，自我創造不會改變終點", "時間推移與經驗累積，可能讓人建立起新的核心價值", "年輕人應及早設定唯一不變的目標，並努力貫徹實行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00281', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我們都有過因害怕而躲在陰影中的經驗，持續凝視黑暗的人，一開始看見的是黑暗，漸漸地在黑暗 中產生各式各樣的幻影，而被自己想像出來的闇黑吞噬。」下列選項，最接近文意的是：', '["三人成虎", "杯弓蛇影", "先入為主", "作繭自縛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
